import React, { useState, useEffect, useCallback, useRef } from 'react';
import axios from 'axios';
import Timer from './Timer';
import AntiCheating from '../utils/antiCheating';

const QuizPage = ({ quizId, teamInfo, onSubmit, onTimeout }) => {
  const [questions, setQuestions] = useState([]);
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
  const [answers, setAnswers] = useState({});
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [tabSwitchCount, setTabSwitchCount] = useState(0);
  const [antiCheatingInstance, setAntiCheatingInstance] = useState(null);
  const [submitting, setSubmitting] = useState(false);
  const [antiCheatingEnabled, setAntiCheatingEnabled] = useState(true);

  // Use refs to avoid dependency cycles
  const answersRef = useRef(answers);
  const submittingRef = useRef(submitting);
  const tabSwitchCountRef = useRef(tabSwitchCount);

  // Update refs when state changes
  useEffect(() => {
    answersRef.current = answers;
  }, [answers]);

  useEffect(() => {
    submittingRef.current = submitting;
  }, [submitting]);

  useEffect(() => {
    tabSwitchCountRef.current = tabSwitchCount;
  }, [tabSwitchCount]);

  // Fetch questions on component mount
  useEffect(() => {
    const fetchQuestions = async () => {
      try {
        setLoading(true);
        const response = await axios.get(`http://localhost:8000/questions/${quizId}`);
        if (response.data && response.data.questions) {
          setQuestions(response.data.questions);
        } else {
          setError('Invalid response format from server');
        }
        setLoading(false);
      } catch (error) {
        console.error('Failed to fetch questions:', error);
        if (error.code === 'ERR_NETWORK') {
          setError('Cannot connect to server. Please make sure the backend is running.');
        } else if (error.response && error.response.status === 404) {
          setError('Quiz session not found. Please start a new quiz.');
        } else {
          setError('Failed to load questions. Please refresh the page.');
        }
        setLoading(false);
      }
    };

    if (quizId) {
      fetchQuestions();
    } else {
      setError('No quiz ID provided');
      setLoading(false);
    }
  }, [quizId]);

  // Handle quiz submission
  const handleSubmitQuiz = useCallback(async () => {
    if (submittingRef.current) return;

    setSubmitting(true);
    setError('');

    try {
      const answersList = Object.entries(answersRef.current).map(([questionId, selectedOption]) => ({
        question_id: parseInt(questionId, 10),
        selected_option: selectedOption
      }));

      // Validate that all questions are answered
      if (answersList.length !== questions.length) {
        throw new Error(`Please answer all questions. Answered: ${answersList.length}/${questions.length}`);
      }

      const response = await axios.post('http://localhost:8000/submit', {
        quiz_id: quizId,
        answers: answersList,
        tab_switch_count: tabSwitchCountRef.current
      }, {
        timeout: 10000 // 10 second timeout
      });

      if (response.data) {
        onSubmit({
          score: response.data.score,
          totalQuestions: response.data.total_questions || questions.length,
          timeTaken: response.data.time_taken_microseconds || 0
        });
      } else {
        throw new Error('Invalid response from server');
      }

    } catch (error) {
      console.error('Failed to submit quiz:', error);

      let errorMessage = 'Failed to submit quiz. ';
      if (error.response) {
        if (error.response.status === 404) {
          errorMessage += 'Quiz session not found. Please start over.';
        } else if (error.response.data && error.response.data.detail) {
          errorMessage += error.response.data.detail;
        } else {
          errorMessage += 'Server error. Please try again.';
        }
      } else if (error.request) {
        errorMessage += 'Cannot reach server. Please check your connection.';
      } else {
        errorMessage += error.message;
      }

      setError(errorMessage);
      setSubmitting(false);
    }
  }, [quizId, questions.length, onSubmit]);

  // Handle auto submission (for time up or violations)
  const handleAutoSubmit = useCallback(() => {
    if (!submittingRef.current && Object.keys(answersRef.current).length > 0) {
      handleSubmitQuiz();
    }
  }, [handleSubmitQuiz]);

  // Handle time up
  const handleTimeUp = useCallback(() => {
    handleAutoSubmit();
    if (onTimeout) {
      onTimeout();
    }
  }, [handleAutoSubmit, onTimeout]);

  // Handle fullscreen exit
  const handleFullscreenExit = useCallback(() => {
    if (tabSwitchCountRef.current >= 3) {
      handleAutoSubmit();
    }
  }, [handleAutoSubmit]);

  // Initialize anti-cheating measures with error handling
  useEffect(() => {
    if (!quizId || antiCheatingInstance || !antiCheatingEnabled) return;

    try {
      console.log('Initializing anti-cheating measures...');
      const ac = new AntiCheating(
        quizId,
        (count) => {
          console.log('Tab switch count:', count);
          setTabSwitchCount(count);
        },
        handleFullscreenExit
      );
      setAntiCheatingInstance(ac);
      console.log('Anti-cheating initialized successfully');
    } catch (error) {
      console.warn('Failed to initialize anti-cheating:', error);
      setAntiCheatingEnabled(false);
      // Show a non-blocking warning to user
      setError('Some anti-cheating features are disabled. Please avoid switching tabs or leaving fullscreen.');
      // Clear error after 5 seconds
      setTimeout(() => setError(''), 5000);
    }

    // Cleanup function
    return () => {
      if (antiCheatingInstance) {
        try {
          antiCheatingInstance.cleanup();
          console.log('Anti-cheating cleaned up');
        } catch (error) {
          console.warn('Error during anti-cheating cleanup:', error);
        }
      }
    };
  }, [quizId, antiCheatingInstance, handleFullscreenExit, antiCheatingEnabled]);

  // Handle option selection
  const handleOptionSelect = useCallback((questionId, option) => {
    if (submittingRef.current) return;

    setAnswers(prev => ({
      ...prev,
      [questionId]: option
    }));

    // Automatically move to next question after selection
    setTimeout(() => {
      setCurrentQuestionIndex(prev => {
        if (prev < questions.length - 1) {
          return prev + 1;
        }
        return prev;
      });
    }, 300);
  }, [questions.length]);

  // Check if all questions are answered
  const allAnswered = Object.keys(answers).length === questions.length && questions.length > 0;

  // Calculate progress percentage
  const progressPercentage = questions.length > 0 
    ? (Object.keys(answers).length / questions.length) * 100 
    : 0;

  // Loading state
  if (loading) {
    return (
      <div className="container">
        <div className="card" style={{ textAlign: 'center', padding: '50px' }}>
          <h2>Loading questions...</h2>
          <div style={{ marginTop: '30px' }}>
            <div className="spinner" style={{
              width: '50px',
              height: '50px',
              border: '5px solid #f3f3f3',
              borderTop: '5px solid #667eea',
              borderRadius: '50%',
              animation: 'spin 1s linear infinite',
              margin: '0 auto'
            }}></div>
          </div>
          <p style={{ marginTop: '20px', color: '#718096' }}>
            Please wait while we prepare your quiz.
          </p>
        </div>
        <style>{`
          @keyframes spin {
            0% { transform: rotate(0deg); }
            100% { transform: rotate(360deg); }
          }
        `}</style>
      </div>
    );
  }

  // Error state
  if (error) {
    return (
      <div className="container">
        <div className="card" style={{ textAlign: 'center' }}>
          <h2 style={{ color: '#f56565' }}>Error</h2>
          <p style={{ color: '#4a5568', margin: '20px 0', lineHeight: '1.6' }}>{error}</p>
          <button 
            className="btn" 
            onClick={() => window.location.reload()}
            type="button"
            style={{ marginRight: '10px' }}
          >
            Refresh Page
          </button>
          <button 
            className="btn btn-secondary" 
            onClick={() => window.location.href = '/'}
            type="button"
          >
            Back to Start
          </button>
        </div>
      </div>
    );
  }

  // No questions state
  if (!questions || questions.length === 0) {
    return (
      <div className="container">
        <div className="card" style={{ textAlign: 'center' }}>
          <h2>No Questions Available</h2>
          <p style={{ color: '#718096', margin: '20px 0' }}>
            There are no questions available for this quiz.
          </p>
          <button 
            className="btn" 
            onClick={() => window.location.href = '/'}
            type="button"
          >
            Back to Start
          </button>
        </div>
      </div>
    );
  }

  const currentQuestion = questions[currentQuestionIndex];

  // Safety check for current question
  if (!currentQuestion) {
    return (
      <div className="container">
        <div className="card" style={{ textAlign: 'center' }}>
          <h2>Invalid Question</h2>
          <p style={{ color: '#718096', margin: '20px 0' }}>
            Unable to load current question.
          </p>
          <button 
            className="btn" 
            onClick={() => window.location.reload()}
            type="button"
          >
            Refresh Page
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="container">
      <div className="card">
        <div className="quiz-header">
          <span className="question-number">
            Q{currentQuestionIndex + 1}/{questions.length}
          </span>
          <Timer 
            initialSeconds={1800} // 30 minutes
            onTimeUp={handleTimeUp}
            isActive={!submitting}
          />
        </div>

        {tabSwitchCount > 0 && (
          <div className="warning-message" role="alert">
            ⚠️ Warning: Tab switching detected ({tabSwitchCount} time{tabSwitchCount !== 1 ? 's' : ''})
          </div>
        )}

        {!antiCheatingEnabled && (
          <div className="warning-message" style={{ backgroundColor: '#fff3cd', color: '#856404' }} role="alert">
            ⚠️ Some anti-cheating features are disabled. Please avoid switching tabs.
          </div>
        )}

        <div className="question-text">
          {currentQuestion.question}
        </div>

        <div className="options-grid">
          {currentQuestion.options.map((option, index) => {
            const isSelected = answers[currentQuestion.id] === option;
            const optionLetter = String.fromCharCode(65 + index); // A, B, C, D

            return (
              <div
                key={`${currentQuestion.id}-${index}`}
                className={`option ${isSelected ? 'selected' : ''} ${submitting ? 'disabled' : ''}`}
                onClick={() => !submitting && handleOptionSelect(currentQuestion.id, option)}
                onKeyPress={(e) => {
                  if ((e.key === 'Enter' || e.key === ' ') && !submitting) {
                    handleOptionSelect(currentQuestion.id, option);
                  }
                }}
                role="button"
                tabIndex={submitting ? -1 : 0}
                aria-label={`Option ${optionLetter}: ${option}`}
                aria-selected={isSelected}
                style={submitting ? { pointerEvents: 'none', opacity: 0.7 } : {}}
              >
                <span style={{ fontWeight: 'bold', marginRight: '10px' }}>
                  {optionLetter}.
                </span>
                {option}
              </div>
            );
          })}
        </div>

        {/* Progress bar */}
        <div style={{ marginTop: '30px' }}>
          <div style={{ 
            width: '100%', 
            height: '8px', 
            backgroundColor: '#e2e8f0', 
            borderRadius: '4px',
            overflow: 'hidden'
          }}>
            <div style={{ 
              width: `${progressPercentage}%`, 
              height: '100%', 
              backgroundColor: '#667eea',
              transition: 'width 0.3s ease'
            }} />
          </div>
        </div>

        {allAnswered && !submitting && (
          <button 
            className="btn btn-secondary"
            onClick={handleSubmitQuiz}
            style={{ marginTop: '20px' }}
            type="button"
            aria-label="Submit quiz"
          >
            Submit Quiz ({Object.keys(answers).length}/{questions.length})
          </button>
        )}

        {submitting && (
          <div 
            style={{ 
              textAlign: 'center', 
              marginTop: '20px', 
              color: '#718096' 
            }}
            aria-live="polite"
          >
            <div className="spinner" style={{
              width: '30px',
              height: '30px',
              border: '3px solid #f3f3f3',
              borderTop: '3px solid #667eea',
              borderRadius: '50%',
              animation: 'spin 1s linear infinite',
              margin: '10px auto'
            }}></div>
            Submitting your answers...
          </div>
        )}

        {/* Progress text */}
        <div 
          style={{ 
            marginTop: '10px', 
            textAlign: 'center', 
            color: '#a0aec0',
            fontSize: '0.9rem'
          }}
        >
          {Object.keys(answers).length} of {questions.length} questions answered
          {currentQuestionIndex < questions.length - 1 && !allAnswered && (
            <span> • Next question will appear after selecting an answer</span>
          )}
        </div>
      </div>

      <style>{`
        .option.disabled {
          opacity: 0.5;
          cursor: not-allowed;
        }
        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
};

export default QuizPage;
